module top_module(
    input [3:0] a,
    input [3:0] b,
    input op,
    output [3:0] result
);reg [3:0] sum_diff;

    always @(*) begin
        if (op == 0) // addition
            sum_diff = a + b;
        else // subtraction
            sum_diff = a - b;
    end

    assign result = sum_diff;

endmodule
